{"version":"NotebookV1","origId":3747736587124201,"name":"01.Build Drivers Standings View","language":"sql","commands":[{"version":"CommandV1","origId":4797249454757953,"guid":"7049a2f3-def4-41f2-b2e3-ac97861f08a1","subtype":"command","commandType":"auto","position":1.0,"command":"%md\n# Build Driver Standings\n\n## Sources\n\n1. fact_session_results\n2. dim_drivers\n\n## Output Columns\n\n1. season\n2. driver id\n3. driver name\n4. nationality\n5. race starts\n6. total points\n7. number of wins\n8. number of podiums\n9. standing position","commandVersion":1,"state":"finished","results":null,"resultDbfsStatus":"INLINED_IN_TREE","resultDbfsErrorMessage":null,"errorSummary":null,"errorTraceType":null,"error":null,"errorDetails":null,"baseErrorDetails":null,"workflows":[],"startTime":0,"submitTime":0,"finishTime":0,"collapsed":false,"bindings":{},"inputWidgets":{},"displayType":"table","width":"auto","height":"auto","xColumns":null,"yColumns":null,"pivotColumns":null,"pivotAggregation":null,"useConsistentColors":false,"customPlotOptions":{},"commentThread":[],"commentsVisible":false,"parentHierarchy":[],"diffInserts":[],"diffDeletes":[],"globalVars":{},"latestUser":"a user","latestUserId":null,"latestAssumeRoleInfo":null,"commandTitle":"","showCommandTitle":false,"hideCommandCode":false,"hideCommandResult":false,"isLockedInExamMode":false,"iPythonMetadata":null,"metadata":{},"streamStates":{},"datasetPreviewNameToCmdIdMap":{},"tableResultIndex":null,"listResultMetadata":[],"subcommandOptions":null,"contentSha256Hex":null,"tableResultSettingsMap":{},"nuid":"291db38c-d350-4bb7-823b-f7549148404f"},{"version":"CommandV1","origId":4797249454757954,"guid":"0b9057ee-44c4-4264-a9cb-f01e6ff0141a","subtype":"command","commandType":"auto","position":2.0,"command":"%md\n![](../04-gold/Untitled.png)","commandVersion":1,"state":"finished","results":null,"resultDbfsStatus":"INLINED_IN_TREE","resultDbfsErrorMessage":null,"errorSummary":null,"errorTraceType":null,"error":null,"errorDetails":null,"baseErrorDetails":null,"workflows":[],"startTime":0,"submitTime":0,"finishTime":0,"collapsed":false,"bindings":{},"inputWidgets":{},"displayType":"table","width":"auto","height":"auto","xColumns":null,"yColumns":null,"pivotColumns":null,"pivotAggregation":null,"useConsistentColors":false,"customPlotOptions":{},"commentThread":[],"commentsVisible":false,"parentHierarchy":[],"diffInserts":[],"diffDeletes":[],"globalVars":{},"latestUser":"a user","latestUserId":null,"latestAssumeRoleInfo":null,"commandTitle":"","showCommandTitle":false,"hideCommandCode":false,"hideCommandResult":false,"isLockedInExamMode":false,"iPythonMetadata":null,"metadata":{},"streamStates":{},"datasetPreviewNameToCmdIdMap":{},"tableResultIndex":null,"listResultMetadata":[],"subcommandOptions":null,"contentSha256Hex":null,"tableResultSettingsMap":{},"nuid":"8d403f73-7816-46d7-bc3f-0545117bbd74"},{"version":"CommandV1","origId":4797249454757955,"guid":"d2379cab-23ca-4302-8815-d971ceb22d6f","subtype":"command","commandType":"auto","position":3.0,"command":"%md\nExtract ources","commandVersion":1,"state":"finished","results":null,"resultDbfsStatus":"INLINED_IN_TREE","resultDbfsErrorMessage":null,"errorSummary":null,"errorTraceType":null,"error":null,"errorDetails":null,"baseErrorDetails":null,"workflows":[],"startTime":0,"submitTime":0,"finishTime":0,"collapsed":false,"bindings":{},"inputWidgets":{},"displayType":"table","width":"auto","height":"auto","xColumns":null,"yColumns":null,"pivotColumns":null,"pivotAggregation":null,"useConsistentColors":false,"customPlotOptions":{},"commentThread":[],"commentsVisible":false,"parentHierarchy":[],"diffInserts":[],"diffDeletes":[],"globalVars":{},"latestUser":"a user","latestUserId":null,"latestAssumeRoleInfo":null,"commandTitle":"","showCommandTitle":false,"hideCommandCode":false,"hideCommandResult":false,"isLockedInExamMode":false,"iPythonMetadata":null,"metadata":{},"streamStates":{},"datasetPreviewNameToCmdIdMap":{},"tableResultIndex":null,"listResultMetadata":[],"subcommandOptions":null,"contentSha256Hex":null,"tableResultSettingsMap":{},"nuid":"06b18916-77fb-4186-9adf-ef37f23d65a4"},{"version":"CommandV1","origId":4797249454757956,"guid":"95b4bcbd-3262-4b21-ac8f-4398112db3c6","subtype":"command","commandType":"auto","position":4.0,"command":"drop view formula1.gold.v_driver_standing;\ncreate or replace view formula1.gold.v_drivers_standing AS\nWITH driver_season_aggregates AS (\n    SELECT \n        r.season AS season,\n        d.driver_id AS driver_id,\n        d.driver_name AS driver_name,\n        d.nationality AS nationality,\n        COUNT(*) AS race_starts,\n        SUM(r.points) AS total_points,\n        COUNT_IF(r.is_win) AS number_of_wins,\n        COUNT_IF(r.is_podium) AS number_of_podiums\n    FROM formula1.gold.fact_session_results AS r\n    JOIN formula1.gold.dim_drivers AS d\n        ON d.driver_id = r.driver_id\n    GROUP BY \n        r.season,\n        d.driver_id,\n        d.driver_name,\n        d.nationality\n)\n\nSELECT\n    RANK() OVER (\n        PARTITION BY season \n        ORDER BY total_points DESC, number_of_wins DESC\n    ) AS standing_position,\n    season,\n    driver_id,\n    driver_name,\n    nationality,\n    race_starts,\n    total_points,\n    number_of_wins,\n    number_of_podiums\nFROM driver_season_aggregates\nORDER BY \n    season DESC, \n    standing_position ASC;","commandVersion":6,"state":"finished","results":{"type":"listResults","data":[{"type":"mimeBundle","data":{"application/vnd.databricks.empty-table+json":{"directive_name":"CreateView"}},"executionCount":null,"arguments":{},"addedWidgets":{},"removedWidgets":[],"datasetInfos":[],"metadata":{"kernelSessionId":"6811df97-5dd360cc35f00b7ef6b50ebf"}}],"arguments":{},"addedWidgets":{},"removedWidgets":[],"datasetInfos":[],"metadata":{"isDbfsCommandResult":false}},"resultDbfsStatus":"INLINED_IN_TREE","resultDbfsErrorMessage":null,"errorSummary":null,"errorTraceType":null,"error":null,"errorDetails":null,"baseEr